// // This module implements a 3-input OR gate followed by a 2-input OR gate, with the outputs of these gates AND'ed together and then inverted.
module bw_u1_aoi32_2x (
    z,
    b1, 
    b2,
    b3,
    a1,
    a2 );
    output z;
    input  b1; 
    input  b2; 
    input  b3; 
    input  a1;
    input  a2;
    assign z = ~(( b1 & b2&b3 ) | ( a1 & a2 ));
endmodule
